from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras
import os

app = Flask(__name__)

def get_db_connection():
    conn = psycopg2.connect(
        dbname=os.getenv('DB_NAME'),
        user=os.getenv('DB_USER'),
        password=os.getenv('DB_PASSWORD'),
        host=os.getenv('DB_HOST'),
        port=os.getenv('DB_PORT')
    )
    return conn

@app.route('/query', methods=['POST'])
def query_db():
    data = request.json
    table = data.get('table')
    columns = data.get('columns', '*')
    filters = data.get('filters', {})

    if not table:
        return jsonify({'error': 'Table name is required'}), 400

    if isinstance(columns, list):
        columns = ', '.join(psycopg2.sql.Identifier(col).as_string(conn) for col in columns)
    else:
        columns = '*'

    where_clauses = []
    values = []
    for col, val in filters.items():
        where_clauses.append(psycopg2.sql.SQL("{} = %s").format(psycopg2.sql.Identifier(col)))
        values.append(val)

    where_sql = psycopg2.sql.SQL(' AND ').join(where_clauses)

    query = psycopg2.sql.SQL("SELECT {} FROM {} WHERE {}").format(
        psycopg2.sql.SQL(columns),
        psycopg2.sql.Identifier(table),
        where_sql
    ) if where_clauses else psycopg2.sql.SQL("SELECT {} FROM {}").format(
        psycopg2.sql.SQL(columns),
        psycopg2.sql.Identifier(table)
    )

    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=psycopg2.extras.DictCursor) as cur:
            cur.execute(query, values)
            results = cur.fetchall()
            return jsonify([dict(row) for row in results])
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        conn.close()

if __name__ == '__main__':
    app.run(debug=True)